cout << "\n";
```

explanation:
## 解説

`set::insert` は新規に挿入できたとき `.second` が `true` になります。これを使うと「初めて見た値か」を判定でき、出現順を保ったまま重複を除けます。

```cpp
set<int> seen;
bool first = true;
for (int x : v) {
    if (seen.insert(x).second) {
        if (!first) cout << " ";
        cout << x;
        first = false;
    }
}
cout << "\n";
```

answer_code:
#include <bits/stdc++.h>
using namespace std;

int main() {
    int n;
    cin >> n;
    vector<int> v(n);
    for (int i = 0; i < n; i++) cin >> v[i];
    set<int> seen;
    bool first = true;
    for (int x : v) {
        if (seen.insert(x).second) {
            if (!first) cout << " ";
            cout << x;
            first = false;
        }
    }
    cout << "\n";
    return 0;
}
